@import '../bosons/margin'
@import '../bosons/padding'
@import '../bosons/YooGridLayout'
@import '../bosons/YooFlexLayout'
@import '../bosons/YooScrollView'



@import '../quarks/animation'
@import '../quarks/border'
@import '../quarks/shadows'
@import '../quarks/typography'
@import '../quarks/flex'

.yoo-selectdate

  &__separator
    +font(var(--greyDarkest), 'xl', '$font-primary', 'medium')

  &__container
    position: relative
    overflow: hidden
    height: 144px

  &__item
    +font(var(--greyLight), 'xl', '$font-primary', 'medium')
    padding: var(--spacing-md) 0
    min-width: 72px
    text-align: center
    cursor: pointer

    &--active
      color: var(--greyDarkest)
      border-top: var(--spacing-tn) solid var(--greyBase)
      border-bottom: var(--spacing-tn) solid var(--greyBase)
      cursor: default

//
// Frow and Columns
// --------------------------------------------------

// Flexible row
//
// Flexible rows contain your columns.

$sizes: map-merge($sizes-mobile, $sizes-desktop)
$sizes-names: map-keys($sizes)

.frow
  display: flex
  flex-wrap: wrap
  justify-content: center
  align-content: flex-start

  +flexbox-rules

  // Columns
  //
  // Generate the various columns widths.

  @if $frow-enable-columns == true
    $all-columns: ()

    @each $size in $sizes-names
      $all-columns: append($all-columns, "[class*=col-#{$size}]", comma)

    &.gutters
      margin-left: -$grid-gutter-width / 2
      margin-right: -$grid-gutter-width / 2

      & > #{$all-columns}
        padding-left: $grid-gutter-width / 2
        padding-right: $grid-gutter-width / 2

    #{$all-columns}
      width: 100%

    @each $size in $sizes-names
      @media (min-width: map-get($sizes, $size))
        @for $denominator from 1 through $grid-max-columns
          @for $numerator from 1 through $denominator
            .col-#{$size}-#{$numerator}-#{$denominator}
              width: percentage($numerator / $denominator)

// Ratios
$golden: 1.618
$octave: (2 / 1)
$major-seventh: (15 / 8)
$minor-seventh: (16 / 9)
$major-sixth: (5 / 3)
$minor-sixth: (8 / 5)
$fifth: (3 / 2)
$fourth: (4 / 3)
$major-third: (5 / 4)
$minor-third: (6 / 5)
$major-second: (9 / 8)
$minor-second: (16 / 15)

$ratio: $golden !default

// Modular Scale logic
@function modular-scale($multiple, $base-size, $ratio)
  $modular-scale: $base-size
  @if $multiple > 0
    @for $i from 1 through $multiple
      $modular-scale: $modular-scale * $ratio
  @if $multiple < 0
    @for $i from 1 through ($multiple * -1)
      $modular-scale: $modular-scale / $ratio
  @return $modular-scale

// Shortcut
@function ms($multiple, $base-size, $ratio)
  @return modular-scale($multiple, $base-size, $ratio)

// Mixin
=modular-scale($property, $multiple, $base-size, $ratio)
  #{$property}: +modular-scale($multiple, $base-size, $ratio)

